param([string]$LogPath, [string]$Pattern, [int]$Context = 2)
Select-String -Path $LogPath -Pattern $Pattern -Context $Context | ForEach-Object {
    Write-Output "=== Match at line $($_.LineNumber) ==="
    if ($_.Context.PreContext) {
        $_.Context.PreContext | ForEach-Object { Write-Output "  $_" }
    }
    Write-Output "> $($_.Line)"
    if ($_.Context.PostContext) {
        $_.Context.PostContext | ForEach-Object { Write-Output "  $_" }
    }
    Write-Output ''
}
